import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.widget.Toast

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent) {
        val uri = intent.data
        if (uri != null && isDeepLinkValid(uri)) {
            when (uri.host) {
                "profile" -> navigateToProfile(uri.pathSegments[1])
                "payment" -> navigateToPayment(uri.pathSegments[1])
                else -> Toast.makeText(this, "Invalid deep link", Toast.LENGTH_SHORT).show()
            }
        } else {
            Toast.makeText(this, "Invalid deep link", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isDeepLinkValid(uri: Uri): Boolean {
        val allowedHosts = setOf("profile", "payment")
        return uri.scheme == "myapp" && uri.host in allowedHosts
    }

    private fun navigateToProfile(userId: String) {
        // Validate and normalize userId before using it
        if (isValidUserId(userId)) {
            // Navigate to ProfileActivity with userId
            val intent = Intent(this, ProfileActivity::class.java)
            intent.putExtra("userId", userId)
            startActivity(intent)
        } else {
            Toast.makeText(this, "Invalid user ID", Toast.LENGTH_SHORT).show()
        }
    }

    private fun navigateToPayment(paymentId: String) {
        // Validate and normalize paymentId before using it
        if (isValidPaymentId(paymentId)) {
            // Navigate to PaymentActivity with paymentId
            val intent = Intent(this, PaymentActivity::class.java)
            intent.putExtra("paymentId", paymentId)
            startActivity(intent)
        } else {
            Toast.makeText(this, "Invalid payment ID", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isValidUserId(userId: String): Boolean {
        // Implement validation logic for userId
        return userId.matches(Regex("[0-9]+"))
    }

    private fun isValidPaymentId(paymentId: String): Boolean {
        // Implement validation logic for paymentId
        return paymentId.matches(Regex("[a-zA-Z0-9]+"))
